solution_code:
#include <iostream>

class Container
{
protected:
    int m_count{};

public:
    int size() const { return m_count; }
    bool empty() const { return m_count == 0; }
};

class Stack : private Container
{
    int m_data[10]{};

public:
    void push(int value)
    {
        m_data[m_count] = value;
        ++m_count;
    }

    int pop()
    {
        --m_count;
        return m_data[m_count];
    }

    int size() const
    {
        return Container::size();
    }
};

int main()
{
    int n{};
    std::cin >> n;

    Stack s{};

    for (int i{ 0 }; i < n; ++i)
    {
        int val{};
        std::cin >> val;
        s.push(val);
    }

    std::cout << "Size: " << s.size() << '\n';

    int count{ s.size() };
    for (int i{ 0 }; i < count; ++i)
    {
        std::cout << s.pop() << '\n';
    }

    return 0;
}
